function renderGlobalSearch(){const input=$('#searchInput'),panel=$('#globalSearchResults'),query=normalizeSearch(input.value.trim());if(!query){panel.hidden=true;input.setAttribute('aria-expanded','false');return}const productMatches=products.filter(product=>normalizeSearch(`${product.name} ${product.supplierSku||''} ${product.internalSku||product.sku||''}`).includes(query)).slice(0,6);const categories=[...new Set(products.map(product=>product.category).filter(Boolean))].filter(category=>normalizeSearch(category).includes(query)).slice(0,6);const orderMatches=orders.filter(order=>normalizeSearch(JSON.stringify(order)).includes(query)).slice(0,6);const customerMap=new Map();for(const order of orders){const key=normalizeSearch(`${order.customerName||''}::${order.customerPhone||''}`);if(!customerMap.has(key))customerMap.set(key,{name:order.customerName||'Sin nombre',phone:order.customerPhone||'',address:order.customerAddress||'',note:order.customerNote||'',orders:[]});customerMap.get(key).orders.push(order.orderNumber)}const customerMatches=[...customerMap.values()].filter(customer=>normalizeSearch(`${customer.name} ${customer.phone} ${customer.address} ${customer.note}`).includes(query)).slice(0,6);const resultButton=(kind,id,title,detail,icon,value='')=>`<button type="button" class="search-result" data-global-kind="${kind}" data-global-id="${escapeHtml(id)}" data-global-value="${escapeHtml(value)}"><span class="search-result-icon">${icon}</span><span class="search-result-copy"><strong>${escapeHtml(title)}</strong><small>${escapeHtml(detail)}</small></span></button>`;panel.innerHTML=globalSearchGroup('Productos',productMatches,product=>resultButton('product',product.id,product.name,`SKU ${product.internalSku||product.sku} · ${product.category}`,'P'))+globalSearchGroup('Categorías',categories,category=>resultButton('category','',category,`${products.filter(product=>product.category===category).length} productos`,'C',category))+globalSearchGroup('Pedidos',orderMatches,order=>resultButton('order',order.id,order.orderNumber,`${order.customerName} · ${order.status}`,'#',order.orderNumber))+globalSearchGroup('Clientes',customerMatches,customer=>resultButton('customer','',customer.name,`${customer.phone||'Sin teléfono'} · ${customer.orders.length} pedido${customer.orders.length===1?'':'s'}`,'CL',customer.name));if(!panel.innerHTML)panel.innerHTML='<div class="search-empty">No encontramos coincidencias.</div>';panel.hidden=false;input.setAttribute('aria-expanded','true')}
function closeGlobalSearch(){const panel=$('#globalSearchResults');panel.hidden=true;$('#searchInput').setAttribute('aria-expanded','false')}

function populateCategories(){const current=$('#categoryFilter').value;const categories=[...new Set(products.map(p=>p.category))].sort();$('#categoryFilter').innerHTML='<option value="all">Todas las categorías</option>'+categories.map(c=>`<option value="${c}">${c}</option>`).join('');$('#categoryFilter').value=categories.includes(current)?current:'all'}
function filtered(){const q=normalizeSearch($('#productSearch')?.value.trim()),cat=$('#categoryFilter').value,status=$('#stockFilter').value;return products.filter(p=>{const match=!q||normalizeSearch(`${p.name} ${p.sku} ${p.supplierSku||''} ${p.internalSku||''}`).includes(q);const catMatch=cat==='all'||p.category===cat,isActive=p.active!==false;const stockMatch=status==='all'||(status==='inactive'&&!isActive)||(status==='low'&&isActive&&p.stock>0&&p.stock<=p.threshold)||(status==='available'&&isActive&&p.stock>p.threshold)||(status==='out'&&isActive&&p.stock===0);return match&&catMatch&&stockMatch})}
function render(){ 
 const list=filtered(),sortedProducts=[...list].sort((a,b)=>{const key=productSort.key;const dir=productSort.direction==='asc'?1:-1;const value=(product)=>{if(key==='margin')return (product.price||0)-(product.cost||0);if(key==='inventoryValue')return (product.cost||0)*(product.stock||0);if(key==='supplierSku')return product.supplierSku||product.sku||'';if(key==='internalSku')return product.internalSku||product.sku||'';return product[key]??''};const av=value(a),bv=value(b);if(typeof av==='string'||typeof bv==='string')return String(av).localeCompare(String(bv),'es')*dir;return (av-bv)*dir;});
 const activeProducts=products.filter(p=>p.active!==false),totalCost=activeProducts.reduce((s,p)=>s+p.cost*p.stock,0),retail=activeProducts.reduce((s,p)=>s+p.price*p.stock,0),margin=retail-totalCost,units=activeProducts.reduce((s,p)=>s+p.stock,0),low=activeProducts.filter(p=>p.stock<=p.threshold).length;
 $('#inventoryCost').textContent=money(totalCost);$('#potentialMargin').textContent=money(margin);$('#marginPercent').textContent=`${retail?Math.round(margin/retail*100):0}% de rentabilidad estimada`;$('#totalUnits').textContent=units.toLocaleString();$('#lowStock').textContent=low;$('#retailValue').textContent=money(retail);$('#activeProducts').textContent=activeProducts.length;setStockBadge(low);$('#lowStockCard').disabled=low<=0;$('#lowStockCard').setAttribute('aria-label',low>0?`Filtrar ${low} producto${low===1?'':'s'} con bajo stock`:'No hay productos con bajo stock');
 $('#resultCount').textContent=`${list.length} producto${list.length===1?'':'s'} en el catálogo`;$('#footerCount').textContent=`Mostrando ${list.length} de ${products.length} productos`;$('#emptyState').hidden=list.length>0;
 $('#productTable').innerHTML=sortedProducts.map(p=>{const unit=p.price-p.cost,percent=p.price?unit/p.price*100:0,isActive=p.active!==false,isLow=isActive&&p.stock<=p.threshold,thumb=p.images?.[0]?.url||p.images?.[0]||'';return `<tr class="${isActive?'':'product-row-inactive'}"><td><button type="button" class="product-cell product-edit-trigger" data-edit="${p.id}" aria-label="Editar ${escapeHtml(p.name)}"><div class="product-thumb ${thumb?'with-image':''}" style="--thumb:${p.themeColor||'#e8ecf5'}">${thumb?`<img src="${escapeHtml(thumb)}" alt="${escapeHtml(p.name)}">`:escapeHtml(p.emoji||'📦')}</div><div class="product-info"><strong>${escapeHtml(p.name)}</strong>${isActive?'':'<span class="inactive-pill">INACTIVO</span>'}</div></button></td><td>${escapeHtml(p.supplierSku||p.sku)}</td><td>${escapeHtml(p.internalSku||p.sku)}</td><td><span class="category-pill">${escapeHtml(p.category)}</span></td><td>${escapeHtml(p.productColor||'Sin especificar')}</td><td>${money(p.cost)}</td><td class="price">${money(p.price)}</td><td><div class="margin"><strong>+${money(unit)}</strong><small>${percent.toFixed(1)}%</small></div></td><td>${p.stock}${isLow?` <span class="stock-label">${p.stock?'BAJO':'AGOTADO'}</span>`:''}</td><td class="price">${money(p.cost*p.stock)}</td><td><div class="row-actions"><button class="row-action" data-edit="${p.id}" aria-label="Editar ${escapeHtml(p.name)}"><span data-row-icon="edit"></span></button><button class="row-action danger" data-delete="${p.id}" aria-label="Eliminar ${escapeHtml(p.name)}"><span data-row-icon="trash"></span></button></div></td></tr>`}).join('');
 document.querySelectorAll('[data-row-icon]').forEach(el=>{el.innerHTML=`<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">${icons[el.dataset.rowIcon]}</svg>`});
}
function internalSkuPreview(){const supplier=$('#productSku').value.trim().toUpperCase(),color=$('#productColor').value.trim().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-zA-Z0-9]+/g,'-').replace(/^-|-$/g,'').toUpperCase();$('#productInternalSku').value=supplier&&color?`${supplier}-${color}`:'Se generará automáticamente'}
function openModal(product,options={}){const copy=options.copy===true;$('#productForm').reset();$('#productId').value=copy?'':product?.id||'';productDraftSource=product||null;productImages=(product?.images||[]).map(image=>typeof image==='string'?image:image.url);$('#modalTitle').textContent=copy?'Copiar producto':product?'Editar producto':'Nuevo producto';if(product){$('#productName').value=product.name;$('#productSku').value=product.supplierSku||product.sku;$('#productCategory').value=product.category;$('#productColor').value=product.productColor||'';$('#productCost').value=product.cost;$('#productPrice').value=product.price;$('#productStock').value=product.stock;$('#productThreshold').value=product.threshold;$('#productDescription').value=product.description||''}else $('#productThreshold').value=5;const editing=Boolean(product&&!copy);$('#copyProductButton').hidden=!editing;$('#toggleProductActiveButton').hidden=!editing;$('#toggleProductActiveButton').textContent=product?.active===false?'Activar':'Desactivar';internalSkuPreview();renderPhotoPreview(productImages);updateFormMargin();$('#productModal').hidden=false;setTimeout(()=>{const target=copy?$('#productColor'):$('#productName');target.focus();if(copy)target.select()},20)}
