function updateSortIndicators(){document.querySelectorAll('[data-sort]').forEach(th=>{th.dataset.active=th.dataset.sort===productSort.key?'true':'false'})}
const normalizeHeader=value=>String(value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]/g,'');
const aliases={sku:['sku','codigo','codigoproducto'],name:['producto','nombre','nombreproducto'],category:['categoria'],productColor:['color'],cost:['costo','costounitario','costogtq'],price:['precio','precioventa','pvp','preciogtq'],stock:['stock','cantidad','existencia'],threshold:['alerta','stockminimo','alertastockbajo'],description:['descripcion']};
function numericValue(value){if(typeof value==='number')return value;let text=String(value??'').replace(/[Q$\s]/g,'');if(text.includes(',')&&text.includes('.'))text=text.replaceAll(',','');else if(text.includes(','))text=text.replace(',','.');return Number(text)}
function valueByAlias(row,key){const found=Object.entries(row).find(([header])=>aliases[key].includes(normalizeHeader(header)));return found?.[1]??''}
async function readProductFiles(fileList){
 const files=[...fileList||[]].filter(file=>String(file.type||'').startsWith('image/'));
 if(!files.length)return [];
 return Promise.all(files.map(file=>new Promise(resolve=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.readAsDataURL(file)})));
}
function isFileDrag(event){
 const types=[...event.dataTransfer?.types||[]];
 return types.includes('Files');
}
async function parseInventoryFile(file){
 if(file.size>5*1024*1024)throw new Error('El archivo supera el máximo de 5 MB.');
 let rawRows=[];
 if(file.name.toLowerCase().endsWith('.csv')){const rows=parseCsv(await file.text()),headers=rows.shift()||[];rawRows=rows.filter(row=>row.some(value=>String(value).trim())).map(row=>Object.fromEntries(headers.map((header,index)=>[header,row[index]??''])))}
 else{if(!window.ExcelJS)throw new Error('No se pudo cargar el lector de Excel. Intenta nuevamente.');const workbook=new ExcelJS.Workbook();await workbook.xlsx.load(await file.arrayBuffer());const sheet=workbook.worksheets[0];if(!sheet)throw new Error('El Excel no contiene hojas.');const headers=sheet.getRow(1).values.slice(1).map(String);for(let rowNumber=2;rowNumber<=sheet.rowCount;rowNumber++){const values=sheet.getRow(rowNumber).values.slice(1).map(value=>value?.result??value?.text??value??'');if(values.some(value=>String(value).trim()))rawRows.push(Object.fromEntries(headers.map((header,index)=>[header,values[index]??''])))} }
 if(!rawRows.length)throw new Error('El archivo no contiene productos.');if(rawRows.length>1000)throw new Error('El archivo supera el máximo de 1,000 productos.');
 const seen=new Set();return rawRows.map((row,index)=>{const product={sku:String(valueByAlias(row,'sku')).trim().toUpperCase(),name:String(valueByAlias(row,'name')).trim(),category:String(valueByAlias(row,'category')||'Sin categoría').trim(),productColor:String(valueByAlias(row,'productColor')||'Sin especificar').trim(),cost:numericValue(valueByAlias(row,'cost')),price:numericValue(valueByAlias(row,'price')),stock:numericValue(valueByAlias(row,'stock')),threshold:numericValue(valueByAlias(row,'threshold')||5),description:String(valueByAlias(row,'description')).trim()};const variantKey=`${product.sku}::${product.productColor.toLocaleLowerCase('es')}`,errors=[];if(!product.sku)errors.push('Falta SKU');if(!product.name)errors.push('Falta producto');for(const field of ['cost','price','stock','threshold'])if(!Number.isFinite(product[field])||product[field]<0)errors.push(`${field} inválido`);if(seen.has(variantKey)&&product.sku)errors.push('SKU y color duplicados');seen.add(variantKey);product.stock=Math.floor(product.stock);product.threshold=Math.floor(product.threshold);return {row:index+2,product,errors,action:products.some(item=>(item.supplierSku||item.sku)===product.sku&&(item.productColor||'Sin especificar').toLocaleLowerCase('es')===product.productColor.toLocaleLowerCase('es'))?'Actualizar':'Crear'}})}
function parseCsv(text){const rows=[];let row=[],value='',quoted=false;for(let index=0;index<text.length;index++){const char=text[index];if(char==='"'){if(quoted&&text[index+1]==='"'){value+='"';index+=1}else quoted=!quoted}else if(char===','&&!quoted){row.push(value);value=''}else if((char==='\n'||char==='\r')&&!quoted){if(char==='\r'&&text[index+1]==='\n')index+=1;row.push(value);rows.push(row);row=[];value=''}else value+=char}if(value||row.length){row.push(value);rows.push(row)}if(rows[0]?.[0])rows[0][0]=rows[0][0].replace(/^\ufeff/,'');return rows}
function showImportPreview(rows,fileName){importRows=rows;const valid=rows.filter(row=>!row.errors.length),errors=rows.length-valid.length,updates=valid.filter(row=>row.action==='Actualizar').length;$('#previewSummary').innerHTML=`<span class="summary-pill">${escapeHtml(fileName)}</span><span class="summary-pill">${valid.length-updates} nuevos</span><span class="summary-pill">${updates} actualizaciones</span>${errors?`<span class="summary-pill error">${errors} con error</span>`:''}`;$('#previewTable').innerHTML=rows.slice(0,50).map(item=>`<tr><td>${item.row}</td><td>${escapeHtml(item.product.sku||'—')}</td><td>${escapeHtml(item.product.name||'—')}</td><td>${item.action}</td><td class="import-status ${item.errors.length?'error':'ok'}">${item.errors.length?escapeHtml(item.errors.join(', ')):'Lista'}</td></tr>`).join('');$('#importPreview').hidden=false;$('#confirmImport').disabled=!valid.length}
