['dragleave','dragend'].forEach(eventName=>$('#photoDropzone').addEventListener(eventName,event=>{if(!isFileDrag(event))return;event.preventDefault();event.stopPropagation();if(eventName==='dragleave'&&event.currentTarget.contains(event.relatedTarget))return;$('#photoDropzone').classList.remove('dragging')}));
