$('#photoPreviewGrid').addEventListener('click',e=>{const view=e.target.closest('[data-view-photo]'),remove=e.target.closest('[data-remove-photo]');if(view){openPhotoViewer(productImages.map(item=>item.url||item),Number(view.dataset.viewPhoto),`Foto ${Number(view.dataset.viewPhoto)+1}`);return}if(!remove)return;productImages=productImages.filter((_,index)=>index!==Number(remove.dataset.removePhoto));renderPhotoPreview(productImages);});
$('#closePhotoViewer').addEventListener('click',closePhotoViewer);closeOnBackdrop('#photoViewerModal',closePhotoViewer);$('#photoViewerPrev').addEventListener('click',()=>shiftPhotoViewer(-1));$('#photoViewerNext').addEventListener('click',()=>shiftPhotoViewer(1));
$('#productForm').addEventListener('submit',async e=>{e.preventDefault();const id=Number($('#productId').value),existing=products.find(p=>p.id===id),base=existing||productDraftSource;const data={name:$('#productName').value.trim(),sku:$('#productSku').value.trim().toUpperCase(),category:$('#productCategory').value.trim(),productColor:$('#productColor').value.trim(),cost:Number($('#productCost').value),price:Number($('#productPrice').value),stock:Number($('#productStock').value),threshold:Number($('#productThreshold').value),description:$('#productDescription').value.trim(),emoji:base?.emoji||'📦',themeColor:base?.themeColor||'#e8ecf5',images:productImages};try{const saved=await api(existing?`/products/${id}`:'/products',{method:existing?'PUT':'POST',body:JSON.stringify(data)});if(existing)products[products.findIndex(p=>p.id===id)]=saved;else products.unshift(saved);populateCategories();render();closeModal();toast(existing?'Producto guardado':'Producto creado',existing?'El inventario se actualizó correctamente.':`Se generó el SKU interno ${saved.internalSku||saved.sku}.`)}catch(error){alert(error.message)}});
$('#exportButton').addEventListener('click',()=>{const rows=[['SKU','Producto','Categoría','Color','Costo (GTQ)','Precio (GTQ)','Stock'],...products.map(p=>[p.sku,p.name,p.category,p.productColor,p.cost,p.price,p.stock])];const csv=rows.map(r=>r.map(v=>`"${String(v).replaceAll('"','""')}"`).join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='inventario-tecnoland.csv';a.click();URL.revokeObjectURL(a.href)});
$('#importButton').addEventListener('click',()=>{$('#importModal').hidden=false;$('#importPreview').hidden=true;$('#confirmImport').disabled=true});$('#chooseFileButton').addEventListener('click',()=>$('#inventoryFile').click());$('#closeImportModal').addEventListener('click',closeImportModal);$('#cancelImport').addEventListener('click',closeImportModal);closeOnBackdrop('#importModal',closeImportModal);
$('#inventoryFile').addEventListener('change',async e=>{const file=e.target.files[0];if(!file)return;$('#chooseFileButton strong').textContent='Leyendo archivo…';try{showImportPreview(await parseInventoryFile(file),file.name)}catch(error){alert(error.message)}finally{$('#chooseFileButton strong').textContent='Selecciona un Excel o CSV'}});
$('#confirmImport').addEventListener('click',async()=>{const valid=importRows.filter(row=>!row.errors.length).map(row=>row.product);if(!valid.length)return;$('#confirmImport').disabled=true;$('#confirmImport').textContent='Importando…';try{const result=await api('/products/bulk',{method:'POST',body:JSON.stringify({products:valid,mergeStrategy:$('#importStrategy').value})});products=await api('/products');populateCategories();render();closeImportModal();toast('Importación completada',`${result.created} creados y ${result.updated} actualizados.`)}catch(error){alert(error.message)}finally{$('#confirmImport').textContent='Importar productos'}});
$('#downloadTemplate').addEventListener('click',()=>{const headers=['SKU','Producto','Categoría','Color','Costo','Precio','Stock','Alerta','Descripción'];const example=['TEC-001','Producto ejemplo','Accesorios','Negro',100,150,10,3,'Descripción del producto'];const csv=[headers,example].map(row=>row.map(value=>`"${String(value).replaceAll('"','""')}"`).join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv;charset=utf-8'}));a.download='plantilla-inventario-tecnoland.csv';a.click();URL.revokeObjectURL(a.href)});
