$('#loginForm').addEventListener('submit',async e=>{e.preventDefault();try{const result=await fetch('/api/auth?route=login',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:$('#loginUsername').value.trim(),password:$('#loginPassword').value})});const data=await result.json();if(!result.ok)throw new Error(data.error||'No se pudo iniciar sesión');setSession({user:data.user});hideLogin();await loadProducts();}catch(error){alert(error.message)}})
