$('#changeLogoButton').addEventListener('click',()=>$('#logoFile').click());
$('#logoFile').addEventListener('change',event=>{const file=event.target.files?.[0];if(!file)return;if(!['image/jpeg','image/png','image/webp','image/svg+xml'].includes(file.type)){alert('Selecciona una imagen JPG, PNG, WebP o SVG.');event.target.value='';return}if(file.size>1024*1024){alert('El logo no puede superar 1 MB.');event.target.value='';return}const reader=new FileReader();reader.onload=()=>{brandLogo=reader.result;localStorage.setItem('tecnoland-brand-logo',brandLogo);applyBrandLogo();toast('Logo actualizado','La barra lateral ya muestra la nueva imagen.')};reader.readAsDataURL(file);event.target.value=''});
