$('#addOrderItem').addEventListener('click',openOrderItemModal);$('#closeOrderItemModal').addEventListener('click',closeOrderItemModal);$('#cancelOrderItemModal').addEventListener('click',closeOrderItemModal);closeOnBackdrop('#orderItemModal',closeOrderItemModal);$('#orderItemSearch').addEventListener('input',()=>{$('#orderItemProduct').value='';renderOrderProductPreview(null);renderOrderProductOptions()});$('#orderItemSearch').addEventListener('focus',renderOrderProductOptions);$('#orderItemSearchResults').addEventListener('click',event=>{const result=event.target.closest('[data-order-product-result]');if(result)selectOrderProduct(Number(result.dataset.orderProductResult))});document.addEventListener('click',event=>{if(!event.target.closest('.order-product-search'))$('#orderItemSearchResults').hidden=true});
$('#orderItemForm').addEventListener('submit',e=>{e.preventDefault();const product=products.find(item=>item.id===Number($('#orderItemProduct').value));const quantity=Math.max(1,Number($('#orderItemQuantity').value||1));if(!product)return;const currentQuantity=orderItems.find(item=>item.productId===product.id)?.quantity||0;const totalRequested=currentQuantity+quantity;if(totalRequested>product.stock){alert(`Solo hay ${product.stock} unidades disponibles de ${product.name}.`);return;}const existing=orderItems.find(item=>item.productId===product.id);if(existing){existing.quantity+=quantity;existing.subtotal=existing.quantity*existing.unitPrice;}else orderItems.push({productId:product.id,productName:product.name,sku:product.supplierSku||product.sku,unitPrice:product.price,unitCost:product.cost,quantity,subtotal:product.price*quantity});closeOrderItemModal();renderOrderForm();saveOrderDraft()});
function updateOrderItemQuantity(index,quantity){const item=orderItems[index],product=products.find(entry=>entry.id===item?.productId);if(!item)return;const next=Math.max(1,Math.floor(Number(quantity)||1)),available=product?.stock||next;if(next>available){alert(`Solo hay ${available} unidades disponibles de ${product?.name||item.productName}.`);renderOrderForm();return}item.quantity=next;item.subtotal=item.unitPrice*next;renderOrderForm();saveOrderDraft()}
$('#orderItemsTable').addEventListener('click',e=>{const remove=e.target.closest('[data-order-remove]');if(remove){orderItems.splice(Number(remove.dataset.orderRemove),1);renderOrderForm();saveOrderDraft();return}const step=e.target.closest('[data-order-quantity-step]');if(step){const index=Number(step.dataset.orderIndex);updateOrderItemQuantity(index,orderItems[index].quantity+Number(step.dataset.orderQuantityStep))}});
$('#orderItemsTable').addEventListener('change',e=>{const input=e.target.closest('[data-order-quantity]');if(input)updateOrderItemQuantity(Number(input.dataset.orderQuantity),input.value)});
$('#allOrdersTable').addEventListener('click',async e=>{const view=e.target.closest('[data-view-order]');if(view){openOrderDetail(Number(view.dataset.viewOrder));return}const remove=e.target.closest('[data-order-delete]');if(!remove)return;const order=orders.find(item=>item.id===Number(remove.dataset.orderDelete));if(!order)return;if(!confirm(`Eliminar pedido ${order.orderNumber} y restaurar inventario?`))return;remove.disabled=true;try{await api(`/orders/${order.id}`,{method:'DELETE'});await loadProducts();await loadOrders();toast('Pedido eliminado','El inventario se restauró correctamente.')}catch(error){alert(error.message)}finally{remove.disabled=false}});
