$('#confirmOrder').addEventListener('click',async e=>{e.preventDefault();const button=e.currentTarget;button.disabled=true;try{const payload={customer:{name:$('#orderCustomerName').value.trim(),phone:$('#orderCustomerPhone').value.trim(),address:$('#orderCustomerAddress').value.trim()},items:orderItems.map(item=>({productId:item.productId,quantity:item.quantity,productName:item.productName,sku:item.sku})),discount:Number($('#orderDiscount').value||0),internalNote:$('#orderInternalNote').value.trim(),courierCompany:$('#orderCourierCompany').value.trim(),trackingNumber:$('#orderTrackingNumber').value.trim(),paymentMethod:$('#orderPaymentMethod').value,deliveryMethod:'courier',status:$('#orderStatus').value,courierHandoffAt:$('#orderCourierHandoffAt')?.value||null,estimatedDeliveryAt:$('#orderEstimatedDeliveryAt')?.value||null};const created=await api('/orders',{method:'POST',body:JSON.stringify(payload)});resetOrderDraft();closeOrderCreateModal();$('#createdOrderNumber').textContent=created.orderNumber;$('#orderSuccessModal').hidden=false;loadProducts().then(openOrders).catch(showInventoryLoadError)}catch(error){alert(error.message)}finally{button.disabled=false}})
